#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, M; scanf("%d %d", &N, &M);
        // allocate hash table for counts up to M (M <= N <= 1e5)
        int *cnt = (int*)calloc(M+2, sizeof(int));
        int x;
        for (int i = 0; i < N; ++i) {
            scanf("%d", &x);
            if (x <= M) cnt[x]++;
        }
        int possible = 1;
        for (int i = 1; i < M; ++i) {
            if (cnt[i] == 0) { possible = 0; break; }
        }
        if (!possible) {
            printf("-1\n");
        } else {
            printf("%d\n", N - cnt[M]);
        }
        free(cnt);
    }
    return 0;
}

