import sys

def solve():
    data = list(map(int, sys.stdin.read().split()))
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it); M = next(it)
        cnt = [0] * (M + 2)
        for _ in range(N):
            x = next(it)
            if x <= M:
                cnt[x] += 1
        possible = all(cnt[i] > 0 for i in range(1, M))
        if not possible:
            out_lines.append('-1')
        else:
            out_lines.append(str(N - cnt[M]))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

